def group_anagrams(words):
    res = []
    for word in words:
        placed = False
        for group in res:
            if sorted(group[0]) == sorted(word):  # O(n²) sort on every comparison
                group.append(word)
                placed = True
                break
        if not placed:
            res.append([word])
    return res

